// Estados verificados 2026-06-06 (PWI y EWI).
// ============================================================================

const rp = $('Resolve Profile').first().json;
const profile = rp.profile;
const jiraId = rp.jira_id;
const areaId = rp.business_area_id;
const isTL = rp.is_tech_lead;

// Resolver nombre de area desde Resolve Area Name (pageId -> Name)
let areaName = null;
if (areaId) {
  const areas = $('Resolve Area Name').first().json.results || [];
  const match = areas.find(a => a.id === areaId);
  areaName = match ? (match.properties?.Name?.title?.[0]?.plain_text || null) : null;
}

function esc(s){ return String(s).replace(/"/g, '\\"'); }

let jql = '';
if (profile === 'stakeholder' || profile === 'lider') {
  // Query amplia: TODOS los PWIs activos. El builder reparte:
  //  - las 4 secciones por estado se filtran al area (en JS)
  //  - la tabla de Prioridades globales usa todos (cola global)
  jql = `project = PWI AND status NOT IN (Done, DEPRECATED) ORDER BY status ASC`;
} else if (profile === 'producto') {
  // PWIs: query amplia (todos los activos). El reparto personal (mis secciones)
  // vs global (Prioridades Globales) se hace en el builder por assignee.
  jql = `project = PWI AND status NOT IN ("IN DEVELOPMENT", Done, DEPRECATED) ORDER BY status ASC`;
} else if (profile === 'it_lead') {
  // Liderazgo de IT (CTO / Head of Technology): vista global de TODO el EWI activo.
  // Sin parte "asignada a mi": trae todos los estados operativos, sin filtrar por assignee.
  // El builder agrupa por estado y arma la tabla de Prioridades globales (caused-by PWI).
  jql = `project = EWI AND status NOT IN (Done, DEPRECATED) ORDER BY status ASC`;
} else if (profile === 'tecnico') {
  // EWIs. Dev comun: lo mio (in progress/code review/blocked propios) + disponibles (ready for dev sin asignar).
  // TL: ademas refinamiento (to/in refinement) + TODOS los BLOCKED del EWI (de cualquier persona).
  const mine = jiraId ? `assignee = "${esc(jiraId)}"` : 'assignee IS EMPTY';
  const devStates = '"IN PROGRESS","CODE REVIEW",BLOCKED';
  const refStates = isTL ? ',"TO REFINEMENT","IN REFINEMENT"' : '';
  // Clausula extra para el TL: cola global -> todos los EWIs en estos estados
  // (sin importar assignee). El builder filtra luego los que son caused-by una PWI.
  const tlGlobal = isTL ? ' OR status IN ("TO REFINEMENT","IN REFINEMENT","READY FOR DEV",BLOCKED)' : '';
  jql = `project = EWI AND ( (${mine} AND status IN (${devStates}${refStates})) OR (assignee IS EMPTY AND status IN ("READY FOR DEV"${isTL ? ',"TO REFINEMENT"' : ''}))${tlGlobal} ) ORDER BY status ASC`;
} else {
  jql = `project = PWI AND assignee IS EMPTY AND status = "To Do"`;
}

return [{ json: { jql, profile, jira_id: jiraId, area_name: areaName, is_tech_lead: isTL,
                  user_id: rp.user_id, publish_user_id: rp.publish_user_id, first_name: rp.first_name } }];

// Identidad
const bj = $('Build JQL').first().json;
const userId = bj.user_id;
const publishUserId = bj.publish_user_id || bj.user_id;
const firstName = bj.first_name || 'che';
const areaName = bj.area_name || 'tu área';
// La respuesta del handler puede venir como objeto o string JSON
let _resp = $json;
if (typeof _resp === 'string') { try { _resp = JSON.parse(_resp); } catch(e){ _resp = {}; } }
if (_resp && _resp.body && !_resp.issues) {
  let b = _resp.body;
  if (typeof b === 'string') { try { b = JSON.parse(b); } catch(e){ b = {}; } }
  _resp = b;
}
const issues = (_resp && _resp.issues) || [];

// --- Aplanador ADF -> texto (Blocked cause: parrafo o tabla) ---
function adfToText(node){
  if (!node || typeof node !== 'object') return '';
  const t = node.type;
  if (t === 'text') return node.text || '';
  if (t === 'hardBreak') return ' ';
  if (t === 'mention') return (node.attrs && node.attrs.text) || '';
  if (t === 'emoji')   return (node.attrs && (node.attrs.text || node.attrs.shortName)) || '';
  if (t === 'inlineCard' || t === 'blockCard') {
    const u = node.attrs && node.attrs.url ? node.attrs.url : '';
    return u ? `[${u}]` : '[link]';
  }
  const kids = Array.isArray(node.content) ? node.content : [];
  if (t === 'tableCell' || t === 'tableHeader') return kids.map(adfToText).filter(Boolean).join(' ').trim();
  if (t === 'tableRow') return kids.map(adfToText).filter(Boolean).join(' · ');
  if (t === 'table')    return kids.map(adfToText).filter(Boolean).join('\n');
  if (t === 'paragraph') return kids.map(adfToText).join('');
  return kids.map(adfToText).filter(Boolean).join('\n');
}
function blockedCauseText(adf){
  if (!adf) return null;
  let txt = adfToText(adf).replace(/\n{2,}/g, '\n').replace(/[ \t]{2,}/g, ' ').trim();
  if (!txt) return null;
  const LIMIT = 280;
  if (txt.length > LIMIT) txt = txt.slice(0, LIMIT - 1).trimEnd() + '…';
  return txt;
}
function daysAgo(iso){ if(!iso) return null; const d=new Date(iso); if(isNaN(d)) return null; return Math.floor((Date.now()-d.getTime())/86400000); }
function agoLabel(iso){ const d=daysAgo(iso); if(d===null) return null; if(d<=0) return 'hoy'; if(d===1) return 'hace 1 día'; return `hace ${d} días`; }
function prioEmoji(p){ p=(p||'').toLowerCase(); if(p==='highest')return'🔺'; if(p==='high')return'🔴'; if(p==='medium')return'🟠'; if(p==='low')return'🟢'; return'⚪'; }
function clip(s,n){ s=String(s||''); return s.length>n ? s.slice(0,n-1).trimEnd()+'…' : s; }

// Extrae la PWI que CAUSA este EWI (link "is caused by" -> inwardIssue del proyecto PWI).
// Replica en JS el filtro que las automatizaciones hacen con el Branch "is caused by".
function causedByPwiKey(links){
  if (!Array.isArray(links)) return null;
  for (const l of links) {
    const t = l.type || {};
    // El EWI "is caused by" la PWI: la PWI aparece como inwardIssue cuando inward = "is caused by".
    if (t.inward === 'is caused by' && l.inwardIssue) {
      const k = l.inwardIssue.key || '';
      if (k.startsWith('PWI-')) return k;
    }
    // Robustez: tambien contemplar el caso espejo (outward causes apuntando a PWI)
    if (t.outward === 'causes' && l.outwardIssue) {
      const k = l.outwardIssue.key || '';
      if (k.startsWith('PWI-')) return k;
    }
  }
  return null;
}
function row(it){
  const f = it.fields || {};
  const a = f.assignee || null;
  return {
    key: it.key, summary: f.summary || '',
    status: f.status ? f.status.name : '',
    assignee: a ? (a.displayName || '') : '',
    assigneeId: a ? (a.accountId || '') : '',
    area: f.customfield_10310 ? (f.customfield_10310.value || f.customfield_10310.name || '') : '',
    priority: f.priority ? f.priority.name : '',
    blockedCause: blockedCauseText(f.customfield_10306),
    blockedSince: f.statuscategorychangedate || null,
    issueType: f.issuetype ? f.issuetype.name : '',
    rank: f.customfield_10019 || '',
    causedByPwi: causedByPwiKey(f.issuelinks)
  };
}
const rows = issues.map(row);
function inStatus(r, arr){ return arr.includes(r.status); }

function table(caption, header, dataRows){
  const head = header.map(h => ({type:'raw_text', text:h}));
  const body = dataRows.map(cells => cells.map(c => ({type:'raw_text', text:String(c)})));
  return { type:'data_table', caption, rows:[head, ...body] };
}
function emptyNote(txt){ return { type:'context', elements:[{type:'mrkdwn', text:txt}] }; }

// Card (slack_icon rocket). opts.useBlockedCause -> body=causa; opts.withButton -> boton Ver en Jira
function pwiCard(r, opts){
  opts = opts || {};
  const ago = agoLabel(r.blockedSince);
  const subParts = [];
  if (r.priority) subParts.push(`${prioEmoji(r.priority)} ${r.priority}`);
  if (r.area)     subParts.push(`📍 ${r.area}`);
  if (ago)        subParts.push(`⏱ ${ago}`);
  let bodyText = opts.useBlockedCause
    ? (r.blockedCause ? r.blockedCause : '_Sin motivo en Blocked cause_')
    : (r.summary || '_Sin descripción_');
  const card = {
    type: 'card',
    block_id: `card-${r.key}`,
    slack_icon: { type: 'icon', name: 'rocket' },
    title:    { type: 'mrkdwn', text: `*${r.key}* · ${clip(r.summary, 80)}` },
    subtitle: { type: 'mrkdwn', text: subParts.join('  ·  ') || '—' },
    body:     { type: 'mrkdwn', text: (bodyText && bodyText.length > 200 ? bodyText.slice(0, 199).trimEnd() + '\u2026' : bodyText) }
  };
  if (opts.withButton) {
    card.actions = [{
      type: 'button',
      text: { type: 'plain_text', text: 'Ver en Jira', emoji: true },
      action_id: `view_${r.key}`,
      url: `https://arduasolutions.atlassian.net/browse/${r.key}`
    }];
  }
  return card;
}
function carousel(cardRows, opts){ return { type:'carousel', elements: cardRows.map(r => pwiCard(r, opts)) }; }
function sectionCarousel(title, rowsArr, opts, emptyTxt){
  const out = [{ type:'header', text:{ type:'plain_text', text:`${title} (${rowsArr.length})`, emoji:true } }];
  if (!rowsArr.length) { out.push(emptyNote(emptyTxt)); return out; }
  const CAP = 10; // Slack: max 10 cards por carousel
  out.push(carousel(rowsArr.slice(0, CAP), opts));
  if (rowsArr.length > CAP) out.push(emptyNote(`_…y ${rowsArr.length - CAP} más._`));
  return out;
}


// Vista global de IT (CTO / Head of Technology). Sin parte "asignada a mi":
// agrupa TODO el EWI activo por estado.

// Refinamiento (global)
const refDisponibles = rows.filter(r => r.status === 'TO REFINEMENT' && !r.assignee);
const refParaHacer   = rows.filter(r => r.status === 'TO REFINEMENT' && r.assignee);
const refEnCurso     = rows.filter(r => r.status === 'IN REFINEMENT');
// Desarrollo (global)
const devDisponibles = rows.filter(r => r.status === 'READY FOR DEV' && !r.assignee);
const devEnCurso     = rows.filter(r => inStatus(r, ['IN PROGRESS','CODE REVIEW']));
const devBloqueados  = rows.filter(r => r.status === 'BLOCKED');

// Cola global: EWIs caused-by una PWI, ordenados por LexoRank
const tlGlobalStates = ['TO REFINEMENT','IN REFINEMENT','READY FOR DEV','BLOCKED'];
const globales = rows
  .filter(r => r.causedByPwi && inStatus(r, tlGlobalStates))
  .filter((r, i, arr) => arr.findIndex(x => x.key === r.key) === i)
  .sort((a, b) => {
    if (!a.rank && !b.rank) return 0;
    if (!a.rank) return 1;
    if (!b.rank) return -1;
    return a.rank < b.rank ? -1 : (a.rank > b.rank ? 1 : 0);
  });

const OPT  = { withButton:true };
const OPTB = { withButton:true, useBlockedCause:true };

const blocks = [
  { type:'section', text:{ type:'mrkdwn', text:`:wave: *Hola, ${firstName}*\nVista Global de IT \u00b7 Tecnolog\u00eda` } },
  { type:'actions', elements:[
    { type:'button', style:'danger', text:{type:'plain_text',text:'Informar bloqueante',emoji:true}, action_id:'report_blocker', value:'blocker' }
  ]},
];

blocks.push({ type:'divider' });
blocks.push({ type:'header', text:{ type:'plain_text', text:'\u25b8 REFINAMIENTO', emoji:true } });
blocks.push(...sectionCarousel('Disponibles', refDisponibles, OPT, '_Nada disponible para refinar._'));
blocks.push(...sectionCarousel('Para hacer', refParaHacer, OPT, '_Nada asignado para refinar._'));
blocks.push(...sectionCarousel('En curso', refEnCurso, OPT, '_Nada refinando ahora._'));

blocks.push({ type:'divider' });
blocks.push({ type:'header', text:{ type:'plain_text', text:'\u25b8 DESARROLLO', emoji:true } });
blocks.push(...sectionCarousel('Disponibles', devDisponibles, OPT, '_Sin tickets disponibles._'));
blocks.push(...sectionCarousel('En curso', devEnCurso, OPT, '_Nada en curso._'));
blocks.push(...sectionCarousel('Bloqueados', devBloqueados, OPTB, '_Sin bloqueos._'));

blocks.push({ type:'divider' });
blocks.push({ type:'header', text:{ type:'plain_text', text:`Prioridades globales (${globales.length})`, emoji:true } });
blocks.push(
  globales.length
    ? table('Prioridades globales', ['EWI','PWI','Requerimiento','Estado','Prioridad'],
        globales.map(r=>[r.key, r.causedByPwi, r.summary, r.status, r.priority||'\u2014']))
    : emptyNote('_Sin EWIs ligados a PWIs en cola._')
);

blocks.push({ type:'context', elements:[{ type:'mrkdwn', text:`Miles \u00b7 ${rows.length} EWIs \u00b7 datos en vivo` }] });

const view={type:'home',blocks};
return [{ json:{ user_id:userId, publish_user_id:publishUserId, view:JSON.stringify(view) } }];
